const __pageData = JSON.parse('{"title":"Разрешение на временное пребывание (aka ВНЖ, Боравак)","description":"Разрешение на временное пребыание в Сербии позволяет иностранным гражданам легально проживать в стране на определённый срок (от 3 месяцев до 3 лет). По основаниям **трудоустройство","frontmatter":{"title":"Разрешение на временное пребывание (aka ВНЖ, Боравак)","description":"Разрешение на временное пребыание в Сербии позволяет иностранным гражданам легально проживать в стране на определённый срок (от 3 месяцев до 3 лет). По основаниям **трудоустройство","tags":["ВНЖ","boravak","боравак","временный вид на жительство","ВНЖ в Сербии","легальное проживание","основания для ВНЖ","процедура подачи заявления","продление ВНЖ"]},"headers":[],"relativePath":"arrival/boravak/index.md","filePath":"arrival/boravak/index.md","lastUpdated":null}');
